import React from 'react';
import './ContextualToolbar.css';
import { 
  Edit3, Copy, Trash2, Copy as Duplicate, Eye, 
  Layers, Settings, RefreshCw, MoreHorizontal 
} from 'lucide-react';

interface ContextualToolbarProps {
  isVisible: boolean;
  selectedComponentId: string | null;
  componentName?: string;
  onEdit?: () => void;
  onCopy?: () => void;
  onDelete?: () => void;
  onDuplicate?: () => void;
  onPreview?: () => void;
  onRegenerate?: () => void;
  onSettings?: () => void;
  onMoreOptions?: () => void;
}

const ContextualToolbar: React.FC<ContextualToolbarProps> = ({
  isVisible,
  selectedComponentId,
  componentName = 'Component',
  onEdit,
  onCopy,
  onDelete,
  onDuplicate,
  onPreview,
  onRegenerate,
  onSettings,
  onMoreOptions
}) => {
  if (!isVisible || !selectedComponentId) {
    return null;
  }

  return (
    <div className="contextual-toolbar">
      <div className="toolbar-header">
        <div className="component-info">
          <Layers size={16} />
          <span className="component-name">{componentName}</span>
        </div>
      </div>

      <div className="toolbar-actions">
        <button 
          className="toolbar-btn primary" 
          onClick={onEdit}
          title="Edit Component"
        >
          <Edit3 size={16} />
          <span>Edit</span>
        </button>

        <button 
          className="toolbar-btn" 
          onClick={onCopy}
          title="Copy Component"
        >
          <Copy size={16} />
          <span>Copy</span>
        </button>

        <button 
          className="toolbar-btn" 
          onClick={onDuplicate}
          title="Duplicate Component"
        >
          <Duplicate size={16} />
          <span>Duplicate</span>
        </button>

        <button 
          className="toolbar-btn" 
          onClick={onPreview}
          title="Preview Component"
        >
          <Eye size={16} />
          <span>Preview</span>
        </button>

        <button 
          className="toolbar-btn" 
          onClick={onRegenerate}
          title="Regenerate Component"
        >
          <RefreshCw size={16} />
          <span>Regenerate</span>
        </button>

        <button 
          className="toolbar-btn" 
          onClick={onSettings}
          title="Component Settings"
        >
          <Settings size={16} />
          <span>Settings</span>
        </button>

        <button 
          className="toolbar-btn danger" 
          onClick={onDelete}
          title="Delete Component"
        >
          <Trash2 size={16} />
          <span>Delete</span>
        </button>

        <button 
          className="toolbar-btn" 
          onClick={onMoreOptions}
          title="More Options"
        >
          <MoreHorizontal size={16} />
        </button>
      </div>
    </div>
  );
};

export default ContextualToolbar;
